## Common patterns

### External links with security

Always use `rel="noopener noreferrer"` when opening external links in new tabs to prevent security vulnerabilities.

```tsx
<Link
  href="https://external-site.com"
  target="_blank"
  rel="noopener noreferrer"
>
  External Link
</Link>
```

### Navigation links with state

When using with routing libraries like React Router, use the `asChild` pattern:

```tsx
import { Link as RouterLink } from 'react-router-dom';

<Link asChild>
  <RouterLink to="/dashboard">
    Dashboard
  </RouterLink>
</Link>
```

### Conditional link styling

Combine with Chakra UI style props for custom styling:

```tsx
<Link
  href="/profile"
  fontWeight="bold"
  textDecoration="none"
  _hover={{ textDecoration: "underline" }}
>
  Profile
</Link>
```

## Testing your implementation

These examples demonstrate how to test your implementation when using Link within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the Link component renders with expected elements and attributes

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Link, NimbusProvider } from "@commercetools/nimbus";
import type { NimbusRouterConfig } from "../nimbus-provider/nimbus-provider.types";

describe("Link - Basic rendering", () => {
  it("renders a link with text content", () => {
    render(
      <NimbusProvider>
        <Link href="/dashboard">Go to Dashboard</Link>
      </NimbusProvider>
    );

    const link = screen.getByRole("link", { name: "Go to Dashboard" });
    expect(link).toBeInTheDocument();
    expect(link).toHaveAttribute("href", "/dashboard");
  });

  it("renders with custom href", () => {
    render(
      <NimbusProvider>
        <Link href="https://commercetools.com">Visit Site</Link>
      </NimbusProvider>
    );

    const link = screen.getByRole("link");
    expect(link).toHaveAttribute("href", "https://commercetools.com");
  });

  it("forwards ref to anchor element", () => {
    const ref = { current: null };
    render(
      <NimbusProvider>
        <Link href="/page" ref={ref}>
          Link with Ref
        </Link>
      </NimbusProvider>
    );

    expect(ref.current).toBeInstanceOf(HTMLAnchorElement);
  });
});
```

### Navigation Tests

Test link navigation behavior and click handling

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Link, NimbusProvider } from "@commercetools/nimbus";
import type { NimbusRouterConfig } from "../nimbus-provider/nimbus-provider.types";

describe("Link - Navigation", () => {
  it("handles click events", async () => {
    const user = userEvent.setup();
    const handleClick = vi.fn();

    render(
      <NimbusProvider router={mockRouter}>
        <Link href="/page" onClick={handleClick}>
          Clickable Link
        </Link>
      </NimbusProvider>
    );

    const link = screen.getByRole("link");
    await user.click(link);

    expect(handleClick).toHaveBeenCalled();
  });

  it("supports keyboard activation with Enter key", async () => {
    const user = userEvent.setup();
    const handleClick = vi.fn();

    render(
      <NimbusProvider router={mockRouter}>
        <Link href="/page" onClick={handleClick}>
          Keyboard Link
        </Link>
      </NimbusProvider>
    );

    const link = screen.getByRole("link");
    link.focus();
    await user.keyboard("{Enter}");

    expect(handleClick).toHaveBeenCalled();
  });

  it("is focusable with Tab key", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <Link href="/page">Focusable Link</Link>
      </NimbusProvider>
    );

    const link = screen.getByRole("link");
    await user.tab();

    expect(link).toHaveFocus();
  });
});
```

### External Link Tests

Test external link behavior with target and rel attributes

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Link, NimbusProvider } from "@commercetools/nimbus";
import type { NimbusRouterConfig } from "../nimbus-provider/nimbus-provider.types";

describe("Link - External links", () => {
  it("opens external links in new tab with proper security attributes", () => {
    render(
      <NimbusProvider>
        <Link
          href="https://external-site.com"
          target="_blank"
          rel="noopener noreferrer"
        >
          External Link
        </Link>
      </NimbusProvider>
    );

    const link = screen.getByRole("link");
    expect(link).toHaveAttribute("target", "_blank");
    expect(link).toHaveAttribute("rel", "noopener noreferrer");
  });

  it("supports download attribute for file downloads", () => {
    render(
      <NimbusProvider>
        <Link href="/files/report.pdf" download="report.pdf">
          Download Report
        </Link>
      </NimbusProvider>
    );

    const link = screen.getByRole("link");
    expect(link).toHaveAttribute("download", "report.pdf");
  });
});
```

